import sqlite3
import os
os.makedirs('data', exist_ok=True)
conn = sqlite3.connect('data/maintenance_erp.db')
c = conn.cursor()

c.execute('''CREATE TABLE users (                 user_id TEXT PRIMARY KEY,                 name TEXT NOT NULL,                 role TEXT NOT NULL CHECK(role IN ('ADMIN', 'HD', 'HM', 'TECH')),                 department TEXT,                 reports_to_hm_id TEXT, is_active INTEGER NOT NULL DEFAULT 1, token_version INTEGER NOT NULL DEFAULT 1,                 FOREIGN KEY(reports_to_hm_id) REFERENCES users(user_id)             )''')
c.execute('''CREATE TABLE user_audit_logs (                 event_id TEXT PRIMARY KEY,                 target_user_id TEXT NOT NULL,                 actor_user_id TEXT NOT NULL,                 action_type TEXT NOT NULL,                 timestamp DATETIME DEFAULT (datetime('now', 'utc')),                 FOREIGN KEY (target_user_id) REFERENCES users(user_id),                 FOREIGN KEY (actor_user_id) REFERENCES users(user_id)             )''')
c.execute('''CREATE TABLE auth_rate_limits (                 employee_id TEXT NOT NULL,                 attempt_timestamp INTEGER NOT NULL             )''')
c.execute('''CREATE TABLE warehouse_inventory (                 sku TEXT PRIMARY KEY,                 stock_level INTEGER,                 unit_cost FLOAT             )''')
c.execute('''CREATE TABLE erp_inventory_ledger (                 transaction_id TEXT PRIMARY KEY,                 part_id TEXT NOT NULL,                 mwo_id TEXT NOT NULL,                 tech_id TEXT NOT NULL,                 quantity_consumed INTEGER NOT NULL CHECK(quantity_consumed > 0),                 transaction_timestamp DATETIME DEFAULT CURRENT_TIMESTAMP,                 FOREIGN KEY(part_id) REFERENCES erp_parts(part_id),                 FOREIGN KEY(mwo_id) REFERENCES work_orders(mwo_id),                 FOREIGN KEY(tech_id) REFERENCES erp_employees(id)             )''')
c.execute('''CREATE TABLE erp_categories (                 id   TEXT PRIMARY KEY,                 name TEXT UNIQUE NOT NULL             )''')
c.execute('''CREATE TABLE erp_departments (                 id   TEXT PRIMARY KEY,                 name TEXT UNIQUE NOT NULL             )''')
c.execute('''CREATE TABLE "erp_equipment" (         equipment_id TEXT PRIMARY KEY,         nomenclature TEXT NOT NULL,         category_id TEXT NOT NULL,         status TEXT NOT NULL CHECK(status IN ('ACTIVE','DEGRADED','OFFLINE','RETIRED')),         department_id TEXT NOT NULL,         assigned_tech_id TEXT, location_id TEXT, assigned_hm_id TEXT,         FOREIGN KEY(category_id) REFERENCES erp_categories(id),         FOREIGN KEY(department_id) REFERENCES erp_departments(id),         FOREIGN KEY(assigned_tech_id) REFERENCES erp_employees(id)     )''')
c.execute('''CREATE TABLE erp_procurement_queue (                 procurement_id TEXT PRIMARY KEY,                 part_id TEXT NOT NULL REFERENCES erp_parts(part_id),                 triggered_at TEXT NOT NULL,                 status TEXT NOT NULL CHECK(status IN ('PENDING', 'APPROVED', 'FULFILLED', 'REJECTED'))             , authorized_quantity INTEGER)''')
c.execute('''CREATE TABLE department_dispatch_rules (             id TEXT PRIMARY KEY,             department_id TEXT NOT NULL,             assigned_hm_id TEXT NOT NULL,             priority_tier INTEGER NOT NULL,             is_active INTEGER NOT NULL DEFAULT 1,             created_at DATETIME DEFAULT CURRENT_TIMESTAMP,             FOREIGN KEY (department_id) REFERENCES erp_departments(id) ON DELETE CASCADE,             FOREIGN KEY (assigned_hm_id) REFERENCES erp_employees(id) ON DELETE CASCADE,             UNIQUE(department_id, priority_tier)          )''')
c.execute('''CREATE TABLE erp_locations (         id TEXT PRIMARY KEY,         name TEXT UNIQUE NOT NULL     )''')
c.execute('''CREATE TABLE "erp_employees" (         id TEXT PRIMARY KEY,         name TEXT NOT NULL,         role TEXT NOT NULL CHECK(role IN ('ADMINISTRATOR', 'ADMIN', 'DM', 'HM', 'TECH')),         pin_hash TEXT NOT NULL,         is_active INTEGER DEFAULT 1,         department_id TEXT REFERENCES erp_departments(id),         reports_to_hm_id TEXT REFERENCES erp_employees(id)     )''')
c.execute('''CREATE TABLE erp_skus (     sku_id TEXT PRIMARY KEY,     nomenclature TEXT NOT NULL,     unit_cost REAL NOT NULL,     reorder_threshold INTEGER NOT NULL,     quantity_on_hand INTEGER DEFAULT 0 )''')
c.execute('''CREATE TABLE erp_parts (         part_id TEXT PRIMARY KEY,         sku_id TEXT NOT NULL,         serial_number TEXT UNIQUE,         status TEXT NOT NULL DEFAULT 'IN_STOCK',         FOREIGN KEY (sku_id) REFERENCES erp_skus(sku_id) ON DELETE RESTRICT     )''')
c.execute('''CREATE TABLE mwo_consumed_parts (     consumption_id TEXT PRIMARY KEY,     mwo_id TEXT NOT NULL,     part_id TEXT NOT NULL,     quantity_consumed INTEGER NOT NULL CHECK (quantity_consumed > 0),     consumed_at REAL NOT NULL,     logged_by_tech_id TEXT NOT NULL,     FOREIGN KEY(mwo_id) REFERENCES work_orders(mwo_id) ON DELETE RESTRICT,     FOREIGN KEY(part_id) REFERENCES erp_parts(part_id) ON DELETE RESTRICT,     FOREIGN KEY(logged_by_tech_id) REFERENCES erp_employees(id) ON DELETE RESTRICT )''')
c.execute('''CREATE TABLE work_orders (         mwo_id TEXT PRIMARY KEY,         status TEXT NOT NULL CHECK (status IN ('UNASSIGNED', 'ASSIGNED', 'IN_PROGRESS', 'PAUSED', 'PENDING_REVIEW', 'COMPLETED', 'PENDING_ROUTING', 'DISPATCHED', 'UNASSIGNED_ESCALATION')),         dm_urgency TEXT,         hm_priority TEXT,         description TEXT,         assigned_tech TEXT REFERENCES erp_employees(id) ON DELETE RESTRICT,         assigned_hm_id TEXT REFERENCES erp_employees(id) ON DELETE RESTRICT,         created_by TEXT REFERENCES erp_employees(id) ON DELETE RESTRICT,         manual_log TEXT,         created_at TEXT,         triaged_at TEXT,         execution_start TEXT,         execution_end TEXT,         completed_at TEXT,         start_date TEXT,         equipment_id TEXT REFERENCES erp_equipment(equipment_id) ON DELETE RESTRICT,          location_id TEXT REFERENCES erp_locations(id) ON DELETE RESTRICT,          material_cost FLOAT,          archival_pdf_path TEXT,          resolution_notes TEXT,          labor_hours REAL,         accumulated_labor_seconds REAL DEFAULT 0.0     )''')
c.execute("INSERT OR IGNORE INTO erp_employees (id, name, role, pin_hash, is_active) VALUES ('ERP-1000', 'Hub Manager', 'HM', '1234', 1)")
c.execute("INSERT OR IGNORE INTO erp_employees (id, name, role, pin_hash, is_active) VALUES ('ERP-3000', 'Test Tech', 'TECH', '1234', 1)")
conn.commit()
conn.close()
print('Schema and Identity Seed successfully instantiated.')
